10	`ifndef VERILATOR
11	module testbench #(
12		parameter AXI_TEST = 0,
13		parameter VERBOSE = 0
14	);
15		reg clk = 1;
16		reg resetn = 0;
17		wire trap;
18	
19		always #5 clk = ~clk;
20	
21		initial begin
22			repeat (100) @(posedge clk);
23			resetn <= 1;
24		end
25	
26		initial begin
27			if ($test$plusargs("vcd")) begin
28				$dumpfile("testbench.vcd");
29				$dumpvars(0, testbench);
30			end
31			repeat (1000000) @(posedge clk);
32			$display("TIMEOUT");
33			$finish;
34		end
35	
36		wire trace_valid;
37		wire [35:0] trace_data;
38		integer trace_file;
39	
40		initial begin
41			if ($test$plusargs("trace")) begin
42				trace_file = $fopen("testbench.trace", "w");
43				repeat (10) @(posedge clk);
44				while (!trap) begin
45					@(posedge clk);
46					if (trace_valid)
47						$fwrite(trace_file, "%x\n", trace_data);
48				end
49				$fclose(trace_file);
50				$display("Finished writing testbench.trace.");
51			end
52		end
53	
54		picorv32_wrapper #(
55			.AXI_TEST (AXI_TEST),
56			.VERBOSE  (VERBOSE)
57		) top (
58			.clk(clk),
59			.resetn(resetn),
60			.trap(trap),
61			.trace_valid(trace_valid),
62			.trace_data(trace_data)
63		);
64	endmodule
65	`endif
